When using {{GridFs.createReadStream}}, the stream always emits the final 'data' event after the 'close' event, which means for libraries that stop listening when close is emitted, the last chunk is always lost.

Reproduction code:
{code:javascript}await new Promise(resolve => {
  const result: string[] = [];

  if (!stream.readable) {
    resolve(result);
  }

  stream.on('data', (data) => {
    console.log('Got chunk');
    result.push(data);
  });

  stream.on('end', () => {
    console.log('Ending');
    resolve(result);
  });

  stream.on('close', () => {
    console.log('Closing');
    resolve(result);
  });
});
{code}
